import{_ as e,o as l,c as r,ay as a}from"./chunks/framework.-lzFfN-z.js";const n="/CoreFront-EndConcepts/udp.png",f=JSON.parse('{"title":"UDP协议","description":"","frontmatter":{},"headers":[],"relativePath":"networkAndBrowsers/udp.md","filePath":"networkAndBrowsers/udp.md","lastUpdated":1779843930000}'),s={name:"networkAndBrowsers/udp.md"};function o(d,t,i,g,P,h){return l(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="udp协议" tabindex="-1"><strong>UDP协议</strong> <a class="header-anchor" href="#udp协议" aria-label="Permalink to &quot;**UDP协议**&quot;">​</a></h1><h2 id="_1-什么是-udp" tabindex="-1">1. 什么是 UDP？ <a class="header-anchor" href="#_1-什么是-udp" aria-label="Permalink to &quot;1. 什么是 UDP？&quot;">​</a></h2><p><strong>UDP</strong> (User Datagram Protocol，用户数据报协议) 是一种<strong>无连接</strong>的、<strong>不可靠</strong>的、基于报文的<strong>传输层</strong>通信协议。在 OSI 模型中，它和 TCP 一样位于第四层（传输层），介于应用层和网络层之间。</p><p>如果说 TCP 是一个极其负责任的“快递总管”（必须签字查收、丢了包赔），那么 <strong>UDP 就是一个效率极高但不管售后的“大喇叭”或“明信片邮递员”</strong>——它只负责把数据打包扔到网络上，至于对方有没有收到、收到的顺序对不对，它一概不问。</p><h2 id="_2-udp-的核心特性" tabindex="-1">2. UDP 的核心特性 <a class="header-anchor" href="#_2-udp-的核心特性" aria-label="Permalink to &quot;2. UDP 的核心特性&quot;">​</a></h2><ul><li><strong>面向无连接</strong>：发送数据之前不需要建立连接（没有三次握手），发送结束后也没有连接释放（没有四次挥手）。</li><li><strong>不可靠交付</strong>：它不保证数据包能成功到达目的地，也不保证按序到达，更没有重传机制。数据发出去后，UDP 就不再管了。</li><li><strong>面向报文</strong>：UDP 对应用层交下来的报文，既不合并，也不拆分，而是<strong>保留这些报文的边界</strong>。应用层交给 UDP 多长的报文，UDP 就发多长。</li><li><strong>无拥塞控制与流量控制</strong>：UDP 永远以恒定的速度发送数据，不管网络是否拥堵。这对于实时应用（如直播）非常重要。</li><li><strong>支持一对一、一对多（广播/多播）通信</strong>：这是 TCP 做不到的。</li><li><strong>首部开销极小</strong>：只有 8 个字节，比 TCP 的 20 字节轻量得多。</li></ul><h2 id="_3-udp-报文首部结构-仅-8-字节" tabindex="-1">3. UDP 报文首部结构 (仅 8 字节) <a class="header-anchor" href="#_3-udp-报文首部结构-仅-8-字节" aria-label="Permalink to &quot;3. UDP 报文首部结构 (仅 8 字节)&quot;">​</a></h2><p>UDP 的简洁在其首部体现得淋漓尽致。</p><table tabindex="0"><thead><tr><th style="text-align:left;">字段名</th><th style="text-align:left;">长度</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>源端口 (Source Port)</strong></td><td style="text-align:left;">16 位</td><td style="text-align:left;">发送方的进程端口号。</td></tr><tr><td style="text-align:left;"><strong>目的端口 (Destination Port)</strong></td><td style="text-align:left;">16 位</td><td style="text-align:left;">接收方的进程端口号。</td></tr><tr><td style="text-align:left;"><strong>长度 (Length)</strong></td><td style="text-align:left;">16 位</td><td style="text-align:left;">UDP 用户数据报的长度（包含首部和数据），最小值为 8。</td></tr><tr><td style="text-align:left;"><strong>校验和 (Checksum)</strong></td><td style="text-align:left;">16 位</td><td style="text-align:left;">检测 UDP 数据报在传输中是否有错。如果有错，直接丢弃。</td></tr></tbody></table><h2 id="_4-udp-vs-tcp-深度对比" tabindex="-1">4. UDP vs. TCP 深度对比 <a class="header-anchor" href="#_4-udp-vs-tcp-深度对比" aria-label="Permalink to &quot;4. UDP vs. TCP 深度对比&quot;">​</a></h2><p>这是网络面试中最经典的问题，通过表格可以直观看出两者的取向：</p><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">UDP</th><th style="text-align:left;">TCP</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>连接性</strong></td><td style="text-align:left;"><strong>无连接</strong></td><td style="text-align:left;">面向连接</td></tr><tr><td style="text-align:left;"><strong>可靠性</strong></td><td style="text-align:left;"><strong>不可靠</strong>（尽力而为）</td><td style="text-align:left;">可靠（保证送达、不乱序）</td></tr><tr><td style="text-align:left;"><strong>传输方式</strong></td><td style="text-align:left;">面向报文（保留数据边界）</td><td style="text-align:left;">面向字节流（无边界）</td></tr><tr><td style="text-align:left;"><strong>传输速度</strong></td><td style="text-align:left;"><strong>极快</strong>（无握手开销）</td><td style="text-align:left;">较慢（机制复杂）</td></tr><tr><td style="text-align:left;"><strong>首部开销</strong></td><td style="text-align:left;"><strong>8 字节</strong></td><td style="text-align:left;">20 ~ 60 字节</td></tr><tr><td style="text-align:left;"><strong>流量/拥塞控制</strong></td><td style="text-align:left;">无</td><td style="text-align:left;">有</td></tr><tr><td style="text-align:left;"><strong>资源消耗</strong></td><td style="text-align:left;">低</td><td style="text-align:left;">高</td></tr><tr><td style="text-align:left;"><strong>适用场景</strong></td><td style="text-align:left;">实时视频、在线游戏、DNS、直播</td><td style="text-align:left;">文件传输、邮件、网页浏览</td></tr><tr><td style="text-align:left;"><strong>优点</strong></td><td style="text-align:left;">安全、快速、漏洞少</td><td style="text-align:left;">稳定、重传机制、拥塞控制机制、断开连接</td></tr><tr><td style="text-align:left;"><strong>缺点</strong></td><td style="text-align:left;">不可靠、不稳定、容易丢包</td><td style="text-align:left;">速度慢、效率低、占用资源、容易被攻击（三次握手-&gt;DDOS攻击）</td></tr></tbody></table><h2 id="_5-udp-的典型应用场景" tabindex="-1">5. UDP 的典型应用场景 <a class="header-anchor" href="#_5-udp-的典型应用场景" aria-label="Permalink to &quot;5. UDP 的典型应用场景&quot;">​</a></h2><p>为什么在明知不可靠的情况下，我们还要使用 UDP？答案是：<strong>低延迟和实时性</strong>。</p><ul><li><strong>实时流媒体/视频会议 (VoIP)</strong>：在语音通话或直播中，丢掉一两个数据包（画面花一下或声音断一下）是可以接受的，但如果因为等待重传而导致长达数秒的延迟，通话就没法进行了。</li><li><strong>在线游戏</strong>：在快节奏游戏中（如 FPS 或 MOBA），即时位置信息比历史位置更重要。丢了旧包没关系，只要下一个新包能快点到就行。</li><li><strong>DNS (域名系统)</strong>：查询域名的请求很短。如果用 TCP，握手就需要 3 个包，查询才 1 个包，太浪费了。用 UDP 一问一答，效率最高。</li><li><strong>广播与多播</strong>：例如局域网内的设备发现、视频广播。TCP 无法实现一对多。</li><li><strong>简单网络协议</strong>：如 DHCP（动态主机配置）、SNMP（简单网络管理）。</li></ul><h2 id="_6-完整流程图" tabindex="-1">6. 完整流程图 <a class="header-anchor" href="#_6-完整流程图" aria-label="Permalink to &quot;6. 完整流程图&quot;">​</a></h2><p><img src="'+n+'" alt="Logo" data-zoomable="true"></p><h2 id="_7-常见问题-faq-与面试热点" tabindex="-1">7. 常见问题 (FAQ) 与面试热点 <a class="header-anchor" href="#_7-常见问题-faq-与面试热点" aria-label="Permalink to &quot;7. 常见问题 (FAQ) 与面试热点&quot;">​</a></h2><h3 id="_7-1-udp-是不可靠的-如果我非要在-udp-上实现可靠传输怎么办" tabindex="-1">7.1 UDP 是不可靠的，如果我非要在 UDP 上实现可靠传输怎么办？ <a class="header-anchor" href="#_7-1-udp-是不可靠的-如果我非要在-udp-上实现可靠传输怎么办" aria-label="Permalink to &quot;7.1 UDP 是不可靠的，如果我非要在 UDP 上实现可靠传输怎么办？&quot;">​</a></h3><ul><li><strong>答案</strong>：这需要在<strong>应用层</strong>（你写的代码里）自己实现可靠性机制。</li><li><strong>具体做法</strong>：你可以模仿 TCP，在应用层逻辑中加入序列号、确认应答（ACK）和超时重传。</li><li><strong>现代案例</strong>：<strong>QUIC 协议</strong>（HTTP/3 的底层）。QUIC 就是基于 UDP 的，但它在 UDP 之上通过算法实现了类似 TCP 的可靠性、拥塞控制，同时又保留了 UDP 快、连接迁移等优点。</li></ul><h3 id="_7-2-udp-报文的大小有限制吗" tabindex="-1">7.2 UDP 报文的大小有限制吗？ <a class="header-anchor" href="#_7-2-udp-报文的大小有限制吗" aria-label="Permalink to &quot;7.2 UDP 报文的大小有限制吗？&quot;">​</a></h3><ul><li><strong>理论上</strong>：UDP 长度字段是 16 位，最大可达 65535 字节。</li><li><strong>实际上</strong>：受限于底层 IP 层和以太网的 <strong>MTU（最大传输单元，通常是 1500 字节）</strong>。 <ul><li>为了避免在 IP 层被切片（切片会导致效率降低且增加丢包风险），建议 UDP 载荷控制在 <strong>1472 字节</strong>以内（1500 - 20 字节 IP 首部 - 8 字节 UDP 首部）。</li></ul></li></ul><h3 id="_7-3-udp-会发生粘包吗" tabindex="-1">7.3 UDP 会发生粘包吗？ <a class="header-anchor" href="#_7-3-udp-会发生粘包吗" aria-label="Permalink to &quot;7.3 UDP 会发生粘包吗？&quot;">​</a></h3><ul><li><strong>答案：绝对不会。</strong></li><li><strong>原因</strong>：粘包是 TCP 这种“面向字节流”协议特有的问题。UDP 是“面向报文”的，它有明确的数据边界。发送方发一个包，接收方就收一个完整的包，不会出现多个包粘在一起的情况。</li></ul><h3 id="_7-4-为什么-udp-适合用于-ddos-攻击-如-ntp-反射攻击" tabindex="-1">7.4 为什么 UDP 适合用于 DDoS 攻击（如 NTP 反射攻击）？ <a class="header-anchor" href="#_7-4-为什么-udp-适合用于-ddos-攻击-如-ntp-反射攻击" aria-label="Permalink to &quot;7.4 为什么 UDP 适合用于 DDoS 攻击（如 NTP 反射攻击）？&quot;">​</a></h3><ul><li><strong>无连接性</strong>：黑客可以非常容易地伪造源 IP 地址发送 UDP 包，而不需要像 TCP 那样建立握手。</li><li><strong>放大效应</strong>：攻击者利用 UDP 向某些服务器（如 DNS 或 NTP）发送微小的请求，诱导服务器向受害者的 IP 发回巨大的响应数据包，从而以极小的代价瘫痪受害者的网络。</li></ul><h3 id="_7-5-校验和-checksum-是必须的吗" tabindex="-1">7.5 校验和（Checksum）是必须的吗？ <a class="header-anchor" href="#_7-5-校验和-checksum-是必须的吗" aria-label="Permalink to &quot;7.5 校验和（Checksum）是必须的吗？&quot;">​</a></h3><ul><li>在 IPv4 中，UDP 校验和是可选的（但强烈建议开启）。</li><li>在 IPv6 中，为了保证基本的安全性，UDP 校验和是<strong>强制性</strong>的。</li></ul><h3 id="_7-6-udp-发送太快会导致接收方缓冲区溢出吗" tabindex="-1">7.6 UDP 发送太快会导致接收方缓冲区溢出吗？ <a class="header-anchor" href="#_7-6-udp-发送太快会导致接收方缓冲区溢出吗" aria-label="Permalink to &quot;7.6 UDP 发送太快会导致接收方缓冲区溢出吗？&quot;">​</a></h3><ul><li><strong>会。</strong> 既然 UDP 没有流量控制，如果发送方拼命发，而接收方来不及从内核缓冲区读取数据，缓冲区就会满。一旦满了，后续到达的 UDP 包会被系统<strong>直接丢弃</strong>。</li></ul><h3 id="_7-7-既然-udp-不可靠-那-dns-丢包了怎么办" tabindex="-1">7.7 既然 UDP 不可靠，那 DNS 丢包了怎么办？ <a class="header-anchor" href="#_7-7-既然-udp-不可靠-那-dns-丢包了怎么办" aria-label="Permalink to &quot;7.7 既然 UDP 不可靠，那 DNS 丢包了怎么办？&quot;">​</a></h3><ul><li>DNS 客户端在发出请求后会启动一个超时定时器。如果在一定时间内没有收到 UDP 响应，客户端会<strong>再次发起请求</strong>。这种简单的重试机制对于 DNS 这种轻量级交互来说成本非常低。</li></ul>',32)])])}const D=e(s,[["render",o]]);export{f as __pageData,D as default};
